/**
 * copy-server-deps.js
 * Copies external server dependencies to dist-server-bundle/node_modules/
 * so the server child process (ELECTRON_RUN_AS_NODE=1) can find them at runtime.
 *
 * Strategy (v2 — 精准闭包复制):
 * Only copy packages listed in dist-server-bundle/package.json (generated by
 * _copy-deps.cjs), which contains the exact closure of vite external deps +
 * their transitive dependencies. This avoids copying ~500 packages that are
 * either devDeps, renderer-only, or already inlined by vite into index.js.
 *
 * Compared to v1 (copy ALL root dependencies then prune), this:
 *  - Reduces copied packages from ~800+ to ~450 (the actual runtime closure)
 *  - Is faster (no prune step needed)
 *  - Is safer (only copies what server-bundle/package.json declares)
 *
 * Additional pruning: strip test/fixtures/docs/examples from copied packages
 * to further reduce size without affecting runtime.
 */
import { cpSync, existsSync, mkdirSync, readFileSync, readdirSync, rmSync, statSync } from 'fs';
import { resolve, dirname, join } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = resolve(__dirname, '..');
const bundleDir = resolve(root, 'dist-server-bundle');
const target = resolve(bundleDir, 'node_modules');
const serverPkgPath = resolve(bundleDir, 'package.json');

// Folders/files that are never needed at runtime and can be stripped from
// every copied package. These are test fixtures, documentation, examples,
// type definitions (server runs as JS, not TS), and build configs.
const STRIP_PER_PACKAGE = new Set([
  'test', 'tests', '__tests__', '__test__', 'spec', 'specs',
  'fixtures', 'fixture', 'testdata', 'test-data', 'test_files',
  'examples', 'example', 'demo', 'demos',
  'docs', 'doc', 'documentation',
  'CHANGELOG.md', 'CHANGES.md', 'HISTORY.md', 'NEWS.md',
  'README.md', 'readme.md', 'README', 'readme',
  'CONTRIBUTING.md', 'CODE_OF_CONDUCT.md', 'LICENSE.md',
  '.eslintrc', '.eslintrc.js', '.eslintrc.json', '.eslintrc.yml',
  '.prettierrc', '.prettierrc.js', '.prettierrc.json',
  '.babelrc', '.babelrc.js', '.babelrc.json', 'babel.config.js',
  'tsconfig.json', 'tsconfig.base.json',
  'jest.config.js', 'jest.config.ts', 'vitest.config.ts',
  'karma.conf.js', 'mocha.opts',
  '.github', '.circleci', '.travis.yml', 'appveyor.yml',
  'Makefile', 'Gulpfile.js', 'gulpfile.js', 'Gruntfile.js',
  'rollup.config.js', 'rollup.config.ts', 'rollup.config.mjs',
  'vite.config.js', 'vite.config.ts',
  'webpack.config.js', 'webpack.config.ts',
  '.nyc_output', 'coverage', '.coverage', 'nyc.config.js',
  '.tap', '.taprc',
  'browserify.config.js',
]);

// @types/* packages — server runs as plain JS, type definitions are dead weight
// Exception: @types/node is needed by some packages at runtime (for re-export)
const SKIP_TYPE_PACKAGES = true;
const TYPE_PACKAGE_WHITELIST = new Set([
  '@types/node', // Some packages re-export Node types
]);

// Read the closure from dist-server-bundle/package.json
if (!existsSync(serverPkgPath)) {
  console.error('[copy-server-deps] dist-server-bundle/package.json not found. Run _copy-deps.cjs first.');
  process.exit(1);
}

const serverPkg = JSON.parse(readFileSync(serverPkgPath, 'utf-8'));
const closureDeps = Object.keys(serverPkg.dependencies || {});
console.log(`[copy-server-deps] Closure has ${closureDeps.length} packages to copy`);

mkdirSync(target, { recursive: true });

let copied = 0;
let skipped = 0;
let strippedBytes = 0;

function stripPackage(pkgDir) {
  let stripped = 0;
  const entries = readdirSync(pkgDir, { withFileTypes: true });
  for (const entry of entries) {
    if (STRIP_PER_PACKAGE.has(entry.name)) {
      const full = join(pkgDir, entry.name);
      try {
        const st = statSync(full);
        strippedBytes += st.isDirectory()
          ? duDir(full)
          : st.size;
        rmSync(full, { recursive: true, force: true });
        stripped++;
      } catch { /* ignore */ }
    }
  }
  return stripped;
}

function duDir(dir) {
  let total = 0;
  try {
    const entries = readdirSync(dir, { withFileTypes: true });
    for (const e of entries) {
      const full = join(dir, e.name);
      try {
        if (e.isDirectory()) total += duDir(full);
        else total += statSync(full).size;
      } catch { /* ignore */ }
    }
  } catch { /* ignore */ }
  return total;
}

for (const dep of closureDeps) {
  // Skip @types/* packages (except whitelist)
  if (dep.startsWith('@types/') && SKIP_TYPE_PACKAGES && !TYPE_PACKAGE_WHITELIST.has(dep)) {
    skipped++;
    continue;
  }

  const src = resolve(root, 'node_modules', dep);
  if (!existsSync(src)) {
    console.warn(`[copy-server-deps] Skipping ${dep}: not found at ${src}`);
    skipped++;
    continue;
  }

  const dest = resolve(target, dep);
  try {
    cpSync(src, dest, { recursive: true });
    // Strip non-runtime files from the copied package
    const strippedCount = stripPackage(dest);
    copied++;
  } catch (err) {
    console.error(`[copy-server-deps] Failed to copy ${dep}: ${err.message}`);
  }
}

console.log(`[copy-server-deps] Done: ${copied} packages copied, ${skipped} skipped`);
console.log(`[copy-server-deps] Stripped ~${(strippedBytes / 1024 / 1024).toFixed(0)}MB of test/docs/fixtures`);
